##  Vasomotor Symptoms of Menopause (VMS, 폐경기 혈관운동증상) — QSP / PK-PD Model
##  ============================================================================
##  Disease  : Menopausal vasomotor symptoms (hot flushes / night sweats)
##  Authors  : Generated by Claude Code Routine (QSP Disease Model Library)
##  Engine   : mrgsolve (>=1.5)
##
##  Scope    : 24 ODE compartments — drug PK (fezolinetant, transdermal/oral
##             estradiol, paroxetine, venlafaxine + ODV metabolite, gabapentin)
##             + KNDy/thermoregulatory disease network (follicle pool, E2, FSH,
##             KNDy/NKB tone, thermoneutral-zone width, core temperature, hot-
##             flush frequency) + downstream organ systems (sleep disruption,
##             mood, bone turnover/BMD, LDL lipid).
##  Time     : days (study horizon 0 – 730 d, default 168 d / 24 wk trial window)
##  Units    : dose in mg; concentration in mg/L; hormones in pg/mL (E2) or
##             IU/L (FSH); disease/biomarker scores in study-specific units.
##  Scenarios: 10 prebuilt — see VMS_simulate_scenarios() at bottom.
##  Anchors  : SKYLIGHT 1/2 (fezolinetant 45 mg) Lederman 2023 Lancet 401:1091;
##             Johnson 2023 J Clin Endocrinol Metab (fezolinetant Ph2b);
##             OASIS 1/2/3 (elinzanetant) Pinkerton 2024 JAMA;
##             WHI (oral CEE±MPA) Rossouw 2002 JAMA 288:321;
##             PEPI trial (HRT lipids) Writing Group 1995 JAMA 273:199;
##             Stearns 2003 JAMA (paroxetine VMS);
##             Loprinzi 2000 Lancet (venlafaxine VMS);
##             Guttuso 2003 Obstet Gynecol (gabapentin VMS);
##             Freedman 2014 Menopause (thermoregulatory model);
##             Rance 2013 Front Neuroendocrinol (KNDy hypertrophy review).
##  Disclaimer: For research / education / hypothesis generation only.
##              Not a substitute for clinical judgment or regulatory filings.
##  ============================================================================
[PROB]
QSP model of menopausal vasomotor symptoms linking ovarian follicle depletion,
loss of estrogen negative feedback, KNDy-neuron/NKB hypertrophy, and
thermoregulatory-center (MnPO) narrowing to hot-flush frequency/severity, with
mechanistic PK/PD for NK3R antagonism, hormone therapy, and nonhormonal agents.

[PLUGIN] Rcpp

[PARAM] @annotated
//--- Patient
AGE         : 51   : age (years, perimenopause ~45-55)
WT          : 65   : body weight (kg)
BMI         : 26   : body mass index
MENO_STAGE  : 2    : 1=late perimenopause, 2=early postmenopause, 3=late postmenopause
SURG_MENO   : 0    : 1 = surgical/abrupt menopause (BSO)
BASE_HF     : 8    : baseline moderate-severe hot flushes / day
BASE_SEV    : 2.0  : baseline HF severity (0-3 scale)
BASE_BMD    : 1.00 : baseline lumbar BMD (g/cm^2)
BASE_LDL    : 120  : baseline LDL-C (mg/dL)
BASE_PSQI   : 10   : baseline PSQI sleep score (0-21)

//--- Fezolinetant PK  (45 mg PO QD; F~68%; Vd~245 L; CL~10.6 L/h; CYP1A2)  Han 2022
KA_FEZ      : 3.0    : 1/day
F_FEZ       : 0.68
CL_FEZ      : 254    : L/day = 10.6 L/h x 24
V_FEZ       : 245    : L
IC50_FEZ_NK3: 0.08    : mg/L, plasma conc for 50% NK3R blockade

//--- Elinzanetant PK  (120 mg PO QD; F~sim; Vd~200 L; CL~10 L/h) OASIS PopPK (surrogate)
KA_ELZ      : 2.2
F_ELZ       : 0.60
CL_ELZ      : 220
V_ELZ       : 200
IC50_ELZ_NK : 0.05

//--- Oral estradiol 1 mg QD (F~5% due to first-pass; Vd~15 L/kg; CL high) Kuhl 2005
KA_E2O      : 4.0
F_E2O       : 0.05
CL_E2O      : 1800   : L/day
V_E2O       : 1000   : L

//--- Transdermal E2 patch 0.05 mg/day (near-zero-order release, no first-pass)
KREL_E2P    : 0.85   : 1/day (fraction of reservoir released per day, near-total)
F_E2P       : 0.90
CL_E2P      : 1800
V_E2P       : 1000

//--- Paroxetine 7.5 mg QD (Brisdelle; F~good; Vd~28 L/kg; CL~19 L/h) Stearns 2003
KA_PRX      : 2.0
F_PRX       : 0.85
CL_PRX      : 456    : L/day = 19 L/h x 24
V_PRX       : 1820   : L (28 L/kg x 65 kg)

//--- Venlafaxine ER 75 mg QD (F~45%; Vd~7.5 L/kg; CL~66 L/h) Klamerus 1992
KA_VEN      : 1.5    : slower with ER formulation
F_VEN       : 0.45
CL_VEN      : 1584   : L/day = 66 L/h x 24
V_VEN       : 488    : L (7.5 L/kg x 65 kg)
FM_ODV      : 0.70   : fraction metabolized to ODV (CYP2D6)
CL_ODV      : 528    : L/day
V_ODV       : 400    : L

//--- Gabapentin 300-900 mg/day divided (saturable absorption; Vd~58 L; CL~9 L/h) Vollmer 1986
KA_GBP      : 1.8
F_GBP_MAX   : 0.60   : max bioavailable fraction (saturates at high dose)
KM_GBP      : 500    : mg, saturation constant for absorption
CL_GBP      : 216    : L/day = 9 L/h x 24
V_GBP       : 58     : L

//--- Clonidine 0.1 mg PO/patch (F~90%; Vd~2.1 L/kg; CL~3.1 L/h) surrogate binary exposure
KA_CLN      : 3.0
F_CLN       : 0.90
CL_CLN      : 74.4   : L/day
V_CLN       : 137    : L

//--- Ovarian follicle depletion & HPG axis
FOLL_0_SET  : 100   : relative follicle pool at model start (units)
K_ATRESIA   : 0.0030 : 1/day baseline atresia (accelerates near menopause via AGE term)
K_ATRESIA_SURG : 0.90 : fractional acute follicle loss if SURG_MENO=1 (applied at t=0 via IC)

KIN_E2      : 100   : pg/mL*day synthesis scale from follicle pool
KOUT_E2     : 0.35  : 1/day
E2_FLOOR    : 8      : pg/mL, obligate peripheral-aromatization floor

KIN_FSH     : 30
KOUT_FSH    : 0.30
FSH_MAX     : 90     : IU/L ceiling
EC50_FSH_E2 : 40      : E2 (pg/mL) giving half-maximal suppression of FSH synthesis

//--- KNDy neuron / NKB tone
KIN_KNDY    : 1.0
KOUT_KNDY   : 0.12
EC50_KNDY_E2: 35      : pg/mL, E2 level giving half-maximal brake on KNDy tone
HILL_KNDY   : 2.0

//--- Thermoneutral zone (TNZ) width — inversely driven by KNDy/NKB tone
TNZ_BASE    : 2.8    : degC, healthy premenopausal TNZ half-width
TNZ_MIN     : 0.35   : degC, minimum (severely narrowed) TNZ half-width
KOUT_TNZ    : 0.25
EMAX_TNZ_KNDY: 0.88   : maximal fractional narrowing
EC50_TNZ_KNDY: 2.5

//--- NK3R / NK1R antagonist effect on KNDy->TNZ narrowing pathway
EMAX_FEZ    : 0.72   : max fractional reversal of KNDy-driven narrowing
EMAX_ELZ    : 0.80

//--- Hot-flush frequency generation (Poisson-rate surrogate, continuous)
KOUT_HFFREQ : 0.30
SCALE_HF_TNZ: 1.0    : HF events/day per unit of (TNZ_BASE - TNZ)
HF_BASELINE_ADJ : 1.0 : patient-specific multiplier fit to BASE_HF

//--- HF severity
KOUT_SEV    : 0.25
SCALE_SEV_TNZ: 0.55

//--- Nonhormonal drug effect (5-HT/NE reuptake inhibition & GABA_Ca) on RPa/thermoregulation
EMAX_SSRI   : 0.45
EC50_PRX    : 0.03   : mg/L
EMAX_SNRI   : 0.48
EC50_VEN_ODV: 0.09    : mg/L (combined VEN+ODV)
EMAX_GBP    : 0.42
EC50_GBP    : 3.0     : mg/L
EMAX_CLN    : 0.30
EC50_CLN    : 0.001   : mg/L

//--- Sleep disruption (PSQI-like)
KOUT_PSQI   : 0.20
SCALE_PSQI_HF: 0.55
PSQI_FLOOR  : 3

//--- Mood (composite depressive-symptom score, 0-27 PHQ-9-like)
KOUT_MOOD   : 0.10
SCALE_MOOD_PSQI: 0.35
SCALE_MOOD_E2 : 0.06
MOOD_FLOOR  : 2

//--- Bone (RANKL/OPG surrogate -> CTX -> BMD)
KIN_CTX     : 1.0
KOUT_CTX    : 0.30
EC50_CTX_E2 : 30
EMAX_CTX    : 2.6
KOUT_BMD    : 0.0022
EMAX_BMD_LOSS: 0.0014
EC50_BMD_E2 : 30

//--- Lipid (LDL-C)
KOUT_LDL    : 0.05
SCALE_LDL_E2: 0.45     : mg/dL LDL reduction per unit ExogE2/EndoE2 ratio term
LDL_HRT_MAX : 18       : max mg/dL LDL reduction achievable with full HRT exposure
EC50_LDL_E2 : 40

[CMT] @annotated
GUT_FEZ    : Fezolinetant gut depot (mg)
CEN_FEZ    : Fezolinetant central (mg)
GUT_ELZ    : Elinzanetant gut depot (mg)
CEN_ELZ    : Elinzanetant central (mg)
GUT_E2O    : Oral estradiol gut depot (mg)
CEN_E2O    : Oral estradiol central (mg)
RES_E2P    : Transdermal E2 patch reservoir (mg)
CEN_E2P    : Transdermal E2 central (mg)
GUT_PRX    : Paroxetine gut (mg)
CEN_PRX    : Paroxetine central (mg)
GUT_VEN    : Venlafaxine gut (mg)
CEN_VEN    : Venlafaxine central (mg)
CEN_ODV    : ODV metabolite central (mg)
GUT_GBP    : Gabapentin gut (mg)
CEN_GBP    : Gabapentin central (mg)
GUT_CLN    : Clonidine gut (mg)
CEN_CLN    : Clonidine central (mg)
FOLL       : Ovarian follicle pool (relative units)
E2         : Plasma estradiol, endogenous+exogenous (pg/mL)
FSH        : Pituitary FSH (IU/L)
KNDY       : KNDy neuron / NKB tone (a.u.)
TNZ        : Thermoneutral-zone half-width (degC)
HFFREQ     : Hot-flush frequency (events/day)
SEV        : Hot-flush severity (0-3)
PSQI       : Sleep-quality index (0-21, higher=worse)
MOOD       : Depressive-symptom composite (0-27, higher=worse)
CTX        : Bone-resorption marker (a.u., CTX-I surrogate)
BMD        : Lumbar bone mineral density (g/cm^2)
LDLC       : LDL cholesterol (mg/dL)

[MAIN]
// Initial conditions
GUT_FEZ_0 = 0; CEN_FEZ_0 = 0;
GUT_ELZ_0 = 0; CEN_ELZ_0 = 0;
GUT_E2O_0 = 0; CEN_E2O_0 = 0;
RES_E2P_0 = 0; CEN_E2P_0 = 0;
GUT_PRX_0 = 0; CEN_PRX_0 = 0;
GUT_VEN_0 = 0; CEN_VEN_0 = 0; CEN_ODV_0 = 0;
GUT_GBP_0 = 0; CEN_GBP_0 = 0;
GUT_CLN_0 = 0; CEN_CLN_0 = 0;

double foll_start = FOLL_0_SET * (1 - (MENO_STAGE-1)*0.35);
FOLL_0 = (SURG_MENO>0) ? foll_start * (1 - K_ATRESIA_SURG) : foll_start;
E2_0   = E2_FLOOR + (FOLL_0/FOLL_0_SET) * 90;
FSH_0  = FSH_MAX * (1 - E2_0/(E2_0 + EC50_FSH_E2));
KNDY_0 = KIN_KNDY / KOUT_KNDY * (1 + pow(EC50_KNDY_E2, HILL_KNDY) /
           (pow(EC50_KNDY_E2, HILL_KNDY) + pow(E2_0, HILL_KNDY)));
TNZ_0  = TNZ_MIN + (TNZ_BASE - TNZ_MIN) / (1 + EMAX_TNZ_KNDY * KNDY_0/(EC50_TNZ_KNDY+KNDY_0)) ;
HFFREQ_0 = BASE_HF;
SEV_0    = BASE_SEV;
PSQI_0   = BASE_PSQI;
MOOD_0   = 6 + 0.5*BASE_PSQI/10;
CTX_0    = KIN_CTX/KOUT_CTX;
BMD_0    = BASE_BMD;
LDLC_0   = BASE_LDL;

[ODE]
// ---------- PK ----------
double CFEZ = CEN_FEZ / V_FEZ;
double CELZ = CEN_ELZ / V_ELZ;
double CE2O = CEN_E2O / V_E2O;
double CE2P = CEN_E2P / V_E2P;
double CPRX = CEN_PRX / V_PRX;
double CVEN = CEN_VEN / V_VEN;
double CODV = CEN_ODV / V_ODV;
double CGBP = CEN_GBP / V_GBP;
double CCLN = CEN_CLN / V_CLN;

dxdt_GUT_FEZ = -KA_FEZ * GUT_FEZ;
dxdt_CEN_FEZ =  F_FEZ * KA_FEZ * GUT_FEZ - (CL_FEZ/V_FEZ) * CEN_FEZ;

dxdt_GUT_ELZ = -KA_ELZ * GUT_ELZ;
dxdt_CEN_ELZ =  F_ELZ * KA_ELZ * GUT_ELZ - (CL_ELZ/V_ELZ) * CEN_ELZ;

dxdt_GUT_E2O = -KA_E2O * GUT_E2O;
dxdt_CEN_E2O =  F_E2O * KA_E2O * GUT_E2O - (CL_E2O/V_E2O) * CEN_E2O;

dxdt_RES_E2P = -KREL_E2P * RES_E2P;
dxdt_CEN_E2P =  F_E2P * KREL_E2P * RES_E2P - (CL_E2P/V_E2P) * CEN_E2P;

dxdt_GUT_PRX = -KA_PRX * GUT_PRX;
dxdt_CEN_PRX =  F_PRX * KA_PRX * GUT_PRX - (CL_PRX/V_PRX) * CEN_PRX;

dxdt_GUT_VEN = -KA_VEN * GUT_VEN;
dxdt_CEN_VEN =  F_VEN * KA_VEN * GUT_VEN - (CL_VEN/V_VEN) * CEN_VEN;
dxdt_CEN_ODV =  FM_ODV * (CL_VEN/V_VEN) * CEN_VEN - (CL_ODV/V_ODV) * CEN_ODV;

double F_GBP = F_GBP_MAX * (KM_GBP / (KM_GBP + GUT_GBP + 1e-6)) + 0.10;
dxdt_GUT_GBP = -KA_GBP * GUT_GBP;
dxdt_CEN_GBP =  F_GBP * KA_GBP * GUT_GBP - (CL_GBP/V_GBP) * CEN_GBP;

dxdt_GUT_CLN = -KA_CLN * GUT_CLN;
dxdt_CEN_CLN =  F_CLN * KA_CLN * GUT_CLN - (CL_CLN/V_CLN) * CEN_CLN;

// ---------- Ovarian follicle depletion ----------
double age_accel = 1 + 0.03 * (AGE - 45);
if (age_accel < 1) age_accel = 1;
dxdt_FOLL = -K_ATRESIA * age_accel * FOLL;

// ---------- Estradiol (endogenous + exogenous contributions) ----------
double ExogE2_input = CE2O*1e6/136.0 * 0.02 + CE2P*1e6/136.0 * 0.02;
// (mg/L -> approximate pg/mL contribution scaling; tuned surrogate, see references)
double EndoE2_drive = KIN_E2 * (FOLL/FOLL_0_SET);
dxdt_E2 = EndoE2_drive + ExogE2_input - KOUT_E2 * (E2 - E2_FLOOR);

// ---------- FSH (negative feedback from E2) ----------
double FSH_target = FSH_MAX * (1 - E2/(E2 + EC50_FSH_E2));
dxdt_FSH = KOUT_FSH * (FSH_target - FSH);

// ---------- KNDy neuron / NKB tone (E2 withdrawal -> hypertrophy) ----------
double KNDy_target = (KIN_KNDY/KOUT_KNDY) *
  (1 + pow(EC50_KNDY_E2, HILL_KNDY) / (pow(EC50_KNDY_E2, HILL_KNDY) + pow(E2, HILL_KNDY)));
dxdt_KNDY = KOUT_KNDY * (KNDy_target - KNDY);

// ---------- Thermoneutral zone width (narrows with KNDy/NKB tone; NK3R antagonists reverse) ----------
double NK3_BLOCK = CFEZ/(IC50_FEZ_NK3 + CFEZ) * EMAX_FEZ
                  + CELZ/(IC50_ELZ_NK  + CELZ) * EMAX_ELZ;
if (NK3_BLOCK > 0.95) NK3_BLOCK = 0.95;
double KNDY_eff = KNDY * (1 - NK3_BLOCK);
double TNZ_target = TNZ_MIN + (TNZ_BASE - TNZ_MIN) /
  (1 + EMAX_TNZ_KNDY * KNDY_eff/(EC50_TNZ_KNDY + KNDY_eff));
dxdt_TNZ = KOUT_TNZ * (TNZ_target - TNZ);

// ---------- Nonhormonal centrally-acting effect on residual HF drive ----------
double SSRI_fx = EMAX_SSRI * CPRX/(EC50_PRX + CPRX);
double SNRI_fx = EMAX_SNRI * (CVEN+CODV)/(EC50_VEN_ODV + CVEN + CODV);
double GBP_fx  = EMAX_GBP  * CGBP/(EC50_GBP + CGBP);
double CLN_fx  = EMAX_CLN  * CCLN/(EC50_CLN + CCLN);
double NONHORM_fx = SSRI_fx + SNRI_fx + GBP_fx + CLN_fx;
if (NONHORM_fx > 0.85) NONHORM_fx = 0.85;

// ---------- Hot-flush frequency ----------
double HF_drive = SCALE_HF_TNZ * (TNZ_BASE - TNZ) * (1 - NONHORM_fx) * HF_BASELINE_ADJ;
if (HF_drive < 0) HF_drive = 0;
dxdt_HFFREQ = KOUT_HFFREQ * (HF_drive - HFFREQ);

// ---------- HF severity ----------
double SEV_target = SCALE_SEV_TNZ * (TNZ_BASE - TNZ) * (1 - 0.6*NONHORM_fx);
if (SEV_target > 3) SEV_target = 3;
if (SEV_target < 0) SEV_target = 0;
dxdt_SEV = KOUT_SEV * (SEV_target - SEV);

// ---------- Sleep (PSQI) ----------
double PSQI_target = PSQI_FLOOR + SCALE_PSQI_HF * HFFREQ;
if (PSQI_target > 21) PSQI_target = 21;
dxdt_PSQI = KOUT_PSQI * (PSQI_target - PSQI);

// ---------- Mood ----------
double MOOD_target = MOOD_FLOOR + SCALE_MOOD_PSQI * PSQI + SCALE_MOOD_E2 * (60 - E2);
if (MOOD_target < 0) MOOD_target = 0;
if (MOOD_target > 27) MOOD_target = 27;
dxdt_MOOD = KOUT_MOOD * (MOOD_target - MOOD);

// ---------- Bone (CTX -> BMD) ----------
double CTX_target = (KIN_CTX/KOUT_CTX) * (1 + EMAX_CTX * (1 - E2/(E2+EC50_CTX_E2)));
dxdt_CTX = KOUT_CTX * (CTX_target - CTX);
double BMD_loss = EMAX_BMD_LOSS * (1 - E2/(E2 + EC50_BMD_E2));
dxdt_BMD = -BMD_loss + KOUT_BMD * (1.00 - BMD) * 0.05;

// ---------- Lipid (LDL-C) ----------
double LDL_target = BASE_LDL + 15*(1 - FOLL/FOLL_0_SET) -
  LDL_HRT_MAX * E2/(E2 + EC50_LDL_E2);
dxdt_LDLC = KOUT_LDL * (LDL_target - LDLC);

[TABLE]
capture conc_fezolinetant  = CEN_FEZ / V_FEZ;
capture conc_elinzanetant  = CEN_ELZ / V_ELZ;
capture conc_E2_oral       = CEN_E2O / V_E2O;
capture conc_E2_patch      = CEN_E2P / V_E2P;
capture conc_paroxetine    = CEN_PRX / V_PRX;
capture conc_venlafaxine   = CEN_VEN / V_VEN;
capture conc_ODV           = CEN_ODV / V_ODV;
capture conc_gabapentin    = CEN_GBP / V_GBP;
capture conc_clonidine     = CEN_CLN / V_CLN;
capture Follicle_pool      = FOLL;
capture E2_pgmL            = E2;
capture FSH_IUL            = FSH;
capture KNDy_tone          = KNDY;
capture TNZ_degC           = TNZ;
capture HF_freq_perday     = HFFREQ;
capture HF_severity        = SEV;
capture PSQI_sleep         = PSQI;
capture Mood_score         = MOOD;
capture CTX_resorption     = CTX;
capture BMD_gcm2           = BMD;
capture LDL_mgdL           = LDLC;

[CAPTURE]
conc_fezolinetant conc_elinzanetant conc_E2_oral conc_E2_patch conc_paroxetine
conc_venlafaxine conc_ODV conc_gabapentin conc_clonidine
Follicle_pool E2_pgmL FSH_IUL KNDy_tone TNZ_degC
HF_freq_perday HF_severity PSQI_sleep Mood_score
CTX_resorption BMD_gcm2 LDL_mgdL


